import org.apache.commons.math3.stat.StatUtils;
import org.apache.commons.math3.util.MathArrays;

import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class NormalizationWithApacheMath {

    public static List<Double> normalizeList(List<Double> originalValues) {
        double[] valuesArray = originalValues.stream().mapToDouble(Double::doubleValue).toArray();

        // 获取最小值和最大值
        double min = StatUtils.min(valuesArray);
        double max = StatUtils.max(valuesArray);

        // 归一化处理
        MathArrays.scaleInPlace(1.0 / (max - min), valuesArray); // scale
        MathArrays.shiftInPlace(-min, valuesArray); // shift to make min = 0

        return Arrays.stream(valuesArray).boxed().collect(Collectors.toList());
    }

    public static void main(String[] args) {
        List<Double> originalValues = List.of(10.0, 20.0, 30.0, 40.0);
        List<Double> normalizedValues = normalizeList(originalValues);

        System.out.println(normalizedValues);
    }
}
```

在这个示例中，我们首先将列表转换为原生的`double`类型数组，然后使用`StatUtils`类来找到最小值和最大值。之后，我们使用`MathArrays`类的`scaleInPlace`方法和`shiftInPlace`方法来执行归一化。

请注意，如果你的数据中的最大值和最小值相同（也就是说数据的变化范围为零），这些归一化的代码将不会正确工作，因为你将会除以零。如果有这种可能性，你需要在代码中添加相应的检查逻辑。

